+func TestMessageValidate(t *testing.T) {
+	tests := []struct {
+		name    string
+		msg     *Message
+		wantErr bool
+		errMsg  string
+	}{
+		{
+			name:    "valid direct message",
+			msg:     NewMessage("mayor/", "gastown/Toast", "Test", "Body"),
+			wantErr: false,
+		},
+		{
+			name:    "valid queue message",
+			msg:     NewQueueMessage("mayor/", "work-requests", "Task", "Body"),
+			wantErr: false,
+		},
+		{
+			name:    "valid channel message",
+			msg:     NewChannelMessage("deacon/", "alerts", "Alert", "Body"),
+			wantErr: false,
+		},
+		{
+			name: "no routing target",
+			msg: &Message{
+				ID:      "msg-001",
+				From:    "mayor/",
+				Subject: "Test",
+			},
+			wantErr: true,
+			errMsg:  "must have exactly one of",
+		},
+		{
+			name: "both to and queue",
+			msg: &Message{
+				ID:      "msg-001",
+				From:    "mayor/",
+				To:      "gastown/Toast",
+				Queue:   "work-requests",
+				Subject: "Test",
+			},
+			wantErr: true,
+			errMsg:  "mutually exclusive",
+		},
+		{
+			name: "both to and channel",
+			msg: &Message{
+				ID:      "msg-001",
+				From:    "mayor/",
+				To:      "gastown/Toast",
+				Channel: "alerts",
+				Subject: "Test",
+			},
+			wantErr: true,
+			errMsg:  "mutually exclusive",
+		},
+		{
+			name: "both queue and channel",
+			msg: &Message{
+				ID:      "msg-001",
+				From:    "mayor/",
+				Queue:   "work-requests",
+				Channel: "alerts",
+				Subject: "Test",
+			},
+			wantErr: true,
+			errMsg:  "mutually exclusive",
+		},
+		{
+			name: "claimed_by on non-queue message",
+			msg: &Message{
+				ID:        "msg-001",
+				From:      "mayor/",
+				To:        "gastown/Toast",
+				Subject:   "Test",
+				ClaimedBy: "gastown/nux",
+			},
+			wantErr: true,
+			errMsg:  "claimed_by is only valid for queue messages",
+		},
+		{
+			name: "claimed_by on queue message is valid",
+			msg: &Message{
+				ID:        "msg-001",
+				From:      "mayor/",
+				Queue:     "work-requests",
+				Subject:   "Test",
+				ClaimedBy: "gastown/nux",
+			},
+			wantErr: false,
+		},
+	}
+
+	for _, tt := range tests {
+		t.Run(tt.name, func(t *testing.T) {
+			err := tt.msg.Validate()
+			if tt.wantErr {
+				if err == nil {
+					t.Error("expected error but got nil")
+				} else if tt.errMsg != "" && !containsString(err.Error(), tt.errMsg) {
+					t.Errorf("error %q should contain %q", err.Error(), tt.errMsg)
+				}
+			} else {
+				if err != nil {
+					t.Errorf("unexpected error: %v", err)
+				}
+			}
+		})
+	}
+}
